mapper.insert:
INSERT INTO flight_track (
icao24, callsign, longitude, latitude,
baro_altitude, velocity, heading, on_ground, origin_country, record_time
) VALUES (
#{icao24}, #{callsign}, #{longitude}, #{latitude},
#{baroAltitude}, #{velocity}, #{heading}, #{onGround}, #{originCountry}, #{recordTime}
)

mapper.select:
SELECT 
FROM flight_track
WHERE icao24 = #{icao24}
AND record_time BETWEEN #{start} AND #{end}
ORDER BY record_time ASC
